import axios from "axios";
import { useEffect, useRef, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useCart } from "./CartContext";
import hashids from "../utils/hashids";

const ArrivalOne = () => {
  const [sortOrder, setSortOrder] = useState("");
  const [services, setServices] = useState([]);
  const [packages, setPackages] = useState([]);
  const [activeTab, setActiveTab] = useState("services"); // Default to services
  const [visibleNoteId, setVisibleNoteId] = useState(null);

  const [hoveredId, setHoveredId] = useState(null);
  const [address, setAddress] = useState("");
  const [centreType, setCentreType] = useState("");
  const [healthInsurance, setHealthInsurance] = useState(false);
  const [cashless, setCashless] = useState(false);
  const [sortPrice, setSortPrice] = useState("");
  const [servicesLoading, setServicesLoading] = useState(false);
  const [packagesLoading, setPackagesLoading] = useState(false);

  // Fetch services (always called on mount)
  const fetchServices = async () => {
    try {
      setServicesLoading(true);
      const res = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/centreService/`
      );
      
      // Handle different response structures
      if (res.data.services && Array.isArray(res.data.services)) {
        setServices(res.data.services);
      } else if (Array.isArray(res.data)) {
        setServices(res.data);
      } else {
        setServices([]);
      }
    } catch (error) {
      console.error("Error fetching services", error.message);
      setServices([]);
    } finally {
      setServicesLoading(false);
    }
  };

  // Fetch packages - will be called when tab changes to packages
  const fetchPackages = async () => {
    try {
      setPackagesLoading(true);
      const res = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/packages/`
      );
            
      // Handle different response structures
      if (res.data.packages && Array.isArray(res.data.packages)) {
        // Paginated response with packages array
        setPackages(res.data.packages);
      } else if (Array.isArray(res.data)) {
        // Direct array response
        setPackages(res.data);
      } else {
        // Unexpected response
        console.warn("Unexpected packages response format:", res.data);
        setPackages([]);
      }
    } catch (error) {
      console.error("Error fetching packages", error.message);
      setPackages([]);
    } finally {
      setPackagesLoading(false);
    }
  };

  // Initial load - fetch services by default
  useEffect(() => {
    fetchServices();
  }, []);

  // Fetch packages when activeTab changes to "packages"
  useEffect(() => {
    if (activeTab === "packages") {
      fetchPackages();
    }
  }, [activeTab]);

  // Handle tab change
  const handleTabChange = (tab) => {
    setActiveTab(tab);
  };

  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      if (
        address.trim() === "" &&
        centreType.trim() === "" &&
        !healthInsurance &&
        !cashless &&
        !sortPrice
      ) {
        // Clear filters - fetch based on active tab
        if (activeTab === "services") {
          fetchServices();
        } else {
          fetchPackages();
        }
      } else {
        handleSearch();
      }
    }, 500);

    return () => clearTimeout(delayDebounce);
  }, [address, centreType, healthInsurance, cashless, sortPrice, activeTab]);

  const handleSearch = async () => {
    try {
      const res = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/centres/searchService&Package`,
        {
          params: {
            address,
            centreType,
            healthInsurance: healthInsurance ? "true" : undefined,
            cashless: cashless ? "true" : undefined,
            sortByPrice: sortPrice,
          },
        }
      );
      
      // Handle services response
      if (res.data.services && Array.isArray(res.data.services)) {
        setServices(res.data.services);
      } else if (Array.isArray(res.data)) {
        setServices(res.data);
      } else {
        setServices([]);
      }
      
      // Handle packages response
      if (res.data.packages && Array.isArray(res.data.packages)) {
        setPackages(res.data.packages);
      } else if (Array.isArray(res.data)) {
        setPackages(res.data);
      } else {
        setPackages([]);
      }
    } catch (err) {
      console.error("Search failed", err);
      setServices([]);
      setPackages([]);
    }
  };

  const { addToCart } = useCart();
  const navigate = useNavigate();

  const handleBookNow = async (serviceId, fromPage) => {
    try {
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/centreService/decrypted/${serviceId}`
      );
      const selectedService = response.data;
      addToCart(selectedService);
      navigate("/cart", { state: { from: fromPage } });
    } catch (error) {
      console.error("Error adding to cart", error);
    }
  };

  const { cartItems } = useCart();

  const isPackageInCart = (pkgId) => {
    return cartItems.some(
      (item) => item.type === "package" && item._id === pkgId
    );
  };

  const handleBookNowPackage = async (packageId, fromPage) => {
    if (isPackageInCart(packageId)) {
      navigate("/cart", { state: { from: fromPage } });
      return;
    }

    try {
      const response = await axios.get(
        `${process.env.REACT_APP_BACKEND_URL}/api/packages/single/${packageId}`
      );
      const selectedPackage = {
        ...response.data,
        type: "package",
      };

      addToCart(selectedPackage);
      navigate("/cart", { state: { from: fromPage } });
    } catch (error) {
      console.error("Error adding package to cart", error);
    }
  };

  // info message card for operative proceudre
  const [showInfoModal, setShowInfoModal] = useState(false);
  const [selectedNote, setSelectedNote] = useState("");

  const handleInfoClick = (note) => {
    setSelectedNote(note || "No additional instructions provided.");
    setShowInfoModal(true);
  };

  const handleCloseInfoModal = () => {
    setShowInfoModal(false);
    setSelectedNote("");
  };

  const toTitleCase = (str = "") => {
    if (!str) return "";
    return str
      .toLowerCase()
      .split(" ")
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join(" ");
  };

  const modalRef = useRef(null);

  useEffect(() => {
    // Handle click outside
    const handleClickOutside = (event) => {
      if (
        modalRef.current &&
        !modalRef.current.contains(event.target) &&
        showInfoModal
      ) {
        showInfoModal(false);
      }
    };

    document.addEventListener("mousedown", handleClickOutside);

    // 🔑 Scroll lock logic
    if (showInfoModal) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "auto";
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
      document.body.style.overflow = "auto";
    };
  }, [showInfoModal]);

  const createSlug = (text) => {
    if (!text) return '';
    return text
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-|-$/g, '');
  };

  // Safe encode function for hashids
  const safeEncodeId = (id) => {
    if (!id) return '';
    try {
      return hashids.encodeHex(id.toString());
    } catch (error) {
      console.error("Error encoding ID:", error);
      return '';
    }
  };

  // Debug logs


  return (
    <section className="arrival-product padding-y-60 section-bg position-relative z-index-1">
      <img
        src="assets/images/gradients/product-gradient.webp"
        alt=""
        className="bg--gradient white-version"
        loading="lazy"
      />

      <div className="container container-two ">
        <div className="section-heading">
          <h3 className="section-heading__title" style={{ fontSize: "30px" }}>
            Popular Healthcare Services
          </h3>
        </div>

        {/* Tabs start */}
        <ul
          className="nav common-tab justify-content-center nav-pills mb-48"
          id="pills-tab"
          role="tablist"
        >
          <li className="nav-item" role="presentation">
            <button
              className={`nav-link ${activeTab === "services" ? "active" : ""}`}
              id="pills-all-tab"
              data-bs-toggle="pill"
              data-bs-target="#pills-all"
              type="button"
              role="tab"
              aria-selected={activeTab === "services"}
              onClick={() => handleTabChange("services")}
            >
              All Services
            </button>
          </li>
          <li className="nav-item" role="presentation">
            <button
              className={`nav-link ${activeTab === "packages" ? "active" : ""}`}
              id="pills-package-tab"
              data-bs-toggle="pill"
              data-bs-target="#pills-package"
              type="button"
              role="tab"
              aria-selected={activeTab === "packages"}
              onClick={() => handleTabChange("packages")}
            >
              All Packages
            </button>
          </li>
        </ul>
        {/* Tabs end */}

        <form action="#" className="filter-form pb-4 d-block">
          <div className="row gy-3">{/* Filter inputs can go here */}</div>
        </form>

        {/* Tab content start */}
        <div className="tab-content" id="pills-tabContent">
          {/* Tab1 content - Services */}
          <div
            className={`tab-pane fade ${
              activeTab === "services" ? "show active" : ""
            }`}
            id="pills-all"
            role="tabpanel"
            aria-labelledby="pills-all-tab"
            tabIndex={0}
          >
            <div className="row gy-4">
              {servicesLoading ? (
                // Loading State
                <div className="col-12">
                  <div className="text-center py-5">
                    <div className="spinner-border text-primary" role="status">
                      <span className="visually-hidden">Loading services...</span>
                    </div>
                    <p className="mt-2">Loading services...</p>
                  </div>
                </div>
              ) : (
                Array.isArray(services) && services.length > 0 ? 
                services.slice(0, 8).map((service, i) => {
                  return (
                    <div className="col-xl-3 col-lg-4 col-sm-6" key={service._id || i}>
                      <div className="product-item h-90 d-flex flex-column overflow-hidden shadow-sm">
                        <div className="product-item__thumb" style={{ height: "180px", flexShrink: 0 }}>
                          <Link
                            to={`/service/${createSlug(service.centre?.centreName)}/${createSlug(service.serviceName)}?category=${createSlug(service.serviceCategory)}&id=${safeEncodeId(service._id)}`}
                            className="link w-100"
                          >
                            <img
                              src={service?.centre?.logo}
                              alt=""
                              className="cover-img w-100"
                              style={{
                                height: "180px",
                                objectFit: "fill",
                              }}
                              loading="lazy"
                            />
                          </Link>
                        </div>

                        {/* Content */}
                        <div className="product-item__content d-flex flex-column p-3 flex-grow-1">
                          <div
                            style={{
                              display: "flex",
                              alignItems: "center",
                              gap: "8px",
                            }}
                          >
                            <h6 className="product-item__title mb-0">
                              <Link
                                to={`/service/${createSlug(service.centre?.centreName)}/${createSlug(service.serviceName)}?category=${createSlug(service.serviceCategory)}&id=${safeEncodeId(service._id)}`}
                                className="link"
                              >
                                {toTitleCase(service.serviceName || "Service Name")}
                              </Link>
                            </h6>

                            {service.serviceCategory === "OPERATIVE PROCEDURES" && (
                              <span
                                title={service.note || "No additional instructions provided."}
                                style={{
                                  cursor: "pointer",
                                  color: "rgb(13, 110, 253)",
                                  marginBottom: "15px",
                                }}
                                onClick={() => handleInfoClick(service.note)}
                              >
                                <i className="fas fa-info-circle"></i>
                              </span>
                            )}
                          </div>

                          <div className="product-item__info d-flex justify-content-between align-items-center mb-3">
                            <span
                              className="product-item__author text-muted small"
                              style={{
                                display: "-webkit-box",
                                WebkitLineClamp: 2,
                                WebkitBoxOrient: "vertical",
                                overflow: "hidden",
                                textOverflow: "ellipsis",
                                maxWidth: "60%",
                                height: "2.9em",
                              }}
                            >
                              <Link
                                to={`/centre/${service?.centre?.centreSlug}/${safeEncodeId(service?.centre?._id)}`}
                                className="link hover-text-decoration-underline"
                              >
                                {toTitleCase(service.centre?.centreName)}
                              </Link>
                            </span>

                            <div className="d-flex align-items-center gap-1 flex-shrink-0">
                              <h6
                                className="product-item__price mb-0 text-success fw-bold"
                                style={{ lineHeight: "1", margin: 0 }}
                              >
                                ₹{service.totalPrice}
                              </h6>
                              {service.discountPrice && (
                                <span
                                  className="product-item__prevPrice text-muted text-decoration-line-through"
                                  style={{ lineHeight: "1", fontSize: "0.9rem" }}
                                >
                                  ₹{service.actualPrice}
                                </span>
                              )}
                            </div>
                          </div>

                          {/* Doctor Info */}
                          {service?.doctors?.length > 0 && (
                            <div className="d-flex align-items-center gap-2 mb-3">
                              <img
                                src={
                                  service.doctors[0].profilePhoto ||
                                  "/assets/images/default-doctor.png"
                                }
                                alt={service.doctors[0].name || "Doctor"}
                                style={{
                                  width: "35px",
                                  height: "35px",
                                  borderRadius: "50%",
                                  objectFit: "cover",
                                }}
                                loading="lazy"
                              />

                              <div className="small" style={{ height: "72px" }}>
                                <span className="fw-semibold d-block">
                                  {service.doctors[0].name || "Dr. Name"}
                                </span>
                                <div
                                  style={{
                                    display: "-webkit-box",
                                    WebkitLineClamp: 2,
                                    WebkitBoxOrient: "vertical",
                                    overflow: "hidden",
                                    textOverflow: "ellipsis",
                                    lineHeight: "1.4em",
                                    maxHeight: "2.8em"
                                  }}
                                  className="d-flex flex-column"
                                >
                                  <span className="text-muted">
                                    {service.doctors[0].specialization
                                      ? toTitleCase(service.doctors[0].specialization)
                                      : "Specialization"}
                                    ,
                                  </span>
                                  <span className="text-muted">
                                    {service.doctors[0].qualification || "Qualification"}
                                  </span>
                                </div>

                                {service.doctors.length > 1 && (
                                  <Link
                                    to={`/service/${createSlug(service.centre?.centreName)}/${createSlug(service.serviceName)}?category=${createSlug(service.serviceCategory)}&id=${safeEncodeId(service._id)}`}
                                    className="text-primary small"
                                  >
                                    + {service.doctors.length - 1} more
                                  </Link>
                                )}
                              </div>
                            </div>
                          )}

                          {/* Bottom Button */}
                          <div className="mt-auto d-flex gap-2">
                            <Link
                              to={`/service/${createSlug(service.centre?.centreName)}/${createSlug(service.serviceName)}?category=${createSlug(service.serviceCategory)}&id=${safeEncodeId(service._id)}`}
                              className="btn btn-outline-light btn-sm pill w-100"
                            >
                              More Details
                            </Link>
                            <button
                              className="btn btn-outline-light btn-sm pill w-100"
                              onClick={() => handleBookNow(safeEncodeId(service?._id), "/")}
                            >
                              Book Now
                            </button>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                }) : (
                  <div className="col-12 text-center py-5">
                    <p className="text-muted">No services found.</p>
                  </div>
                )
              )}
            </div>
          </div>

          {/* Tab2 content - Packages */}
          <div
            className={`tab-pane fade ${
              activeTab === "packages" ? "show active" : ""
            }`}
            id="pills-package"
            role="tabpanel"
            aria-labelledby="pills-package-tab"
            tabIndex={1}
          >
            <div className="row gy-4">
              {packagesLoading ? (
                // Loading State
                <div className="col-12">
                  <div className="text-center py-5">
                    <div className="spinner-border text-primary" role="status">
                      <span className="visually-hidden">Loading packages...</span>
                    </div>
                    <p className="mt-2">Loading packages...</p>
                  </div>
                </div>
              ) : (
                Array.isArray(packages) && packages.length > 0 ? 
                packages.slice(0, 8).map((doc, i) => (
                  <div className="col-xl-3 col-lg-4 col-sm-6" key={doc._id || i}>
                    <div className="product-item h-90 d-flex flex-column overflow-hidden shadow-sm">
                      <div
                        className="product-item__thumb"
                        style={{ height: "180px", flexShrink: 0 }}
                      >
                        <Link
                          to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                          className="link w-100"
                        >
                          <img
                            src={doc?.centre?.logo}
                            alt="Package"
                            style={{ height: "180px", objectFit: "fill" }}
                            className="cover-img w-100"
                            loading="lazy"
                          />
                        </Link>
                      </div>

                      <div className="product-item__content d-flex flex-column p-3 flex-grow-1">
                        <h6 className="product-item__title mb-0">
                          <Link
                            to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                            className="link"
                          >
                            {toTitleCase(doc.packageName)}
                          </Link>
                        </h6>

                        <div className="product-item__info d-flex justify-content-between align-items-center mb-3">
                          <span
                            className="product-item__author text-muted small"
                            style={{
                              display: "-webkit-box",
                              WebkitLineClamp: 2,
                              WebkitBoxOrient: "vertical",
                              overflow: "hidden",
                              textOverflow: "ellipsis",
                              maxWidth: "60%",
                              height: "2.9em",
                            }}
                          >
                            <Link
                              to={`/centre/${doc?.centre?.centreSlug}/${safeEncodeId(doc?.centre?._id)}`}
                              className="link hover-text-decoration-underline"
                            >
                              {toTitleCase(doc.centre?.centreName)}
                            </Link>
                          </span>

                          <div className="d-flex align-items-center gap-1 flex-shrink-0">
                            <h6 className="product-item__price mb-0 text-success fw-bold" style={{ lineHeight: "1", margin: 0 }}>
                              ₹{doc.totalPrice}
                            </h6>
                            {doc.discountPrice ? (
                              <span className="product-item__prevPrice text-decoration-line-through" style={{ lineHeight: "1", fontSize: "0.9rem" }}>
                                ₹{doc.actualPrice}
                              </span>
                            ) : null}
                          </div>
                        </div>

                        <div className="product-item__info package-item__info flx-between gap-2">
                          <div
                            className="product-item__author"
                            style={{ marginTop: "-10px" }}
                          >
                            {doc.services?.slice(0, 2).map((srv, index) => (
                              <p key={srv._id || index}>
                                {toTitleCase(srv.serviceName)}
                              </p>
                            ))}

                            {doc.services?.length > 2 && (
                              <Link
                                to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                                className="link hover-text-decoration-underline text-primary"
                              >
                                + {doc.services.length - 2} more
                              </Link>
                            )}
                          </div>
                        </div>

                        <div className="mt-auto d-flex gap-2">
                          <Link
                            to={`/package/${createSlug(doc.centre?.centreName)}/${createSlug(doc.packageName)}?id=${safeEncodeId(doc._id)}`}
                            className="btn btn-outline-light btn-sm pill w-100"
                          >
                            More Details
                          </Link>
                          <button
                            className="btn btn-outline-light btn-sm pill w-100"
                            onClick={() => handleBookNowPackage(doc._id, "/")}
                          >
                            Book Now
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                )) : (
                  <div className="col-12 text-center py-5">
                    <p className="text-muted">No packages found.</p>
                  </div>
                )
              )}
            </div>
          </div>
        </div>

        <div className="text-center mt-64">
          <Link
            to={activeTab === "services" ? "/all-service" : "/all-package"}
            className="btn btn-main btn-lg pill fw-300"
          >
            {activeTab === "services"
              ? "View All Services"
              : "View All Packages"}
          </Link>
        </div>

        {showInfoModal && (
          <div
            style={{
              position: "fixed",
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              backgroundColor: "rgba(0,0,0,0.5)",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              zIndex: 1000,
            }}
          >
            <div
              style={{
                backgroundColor: "#fff",
                borderRadius: "10px",
                maxWidth: "600px",
                width: "95%",
                maxHeight: "95vh",
                boxShadow: "0 0 10px rgba(0,0,0,0.3)",
                position: "relative",
                overflowY: "auto",
              }}
            >
              {/* Modal Header */}
              <div
                style={{
                  backgroundColor: "#3a3a3a",
                  color: "#fff",
                  padding: "15px 20px",
                  fontSize: "18px",
                  fontWeight: "bold",
                  position: "relative",
                }}
              >
                Notes for Patients
                <button
                  onClick={handleCloseInfoModal}
                  style={{
                    position: "absolute",
                    top: "10px",
                    right: "10px",
                    background: "transparent",
                    border: "none",
                    fontSize: "30px",
                    color: "#fff",
                    cursor: "pointer",
                  }}
                >
                  &times;
                </button>
              </div>

              {/* Modal Body */}
              <div
                style={{
                  padding: "20px",
                  color: "#333",
                  display: "flex",
                  flexDirection: "column",
                  gap: "10px",
                }}
              >
                <p>{selectedNote}</p>
              </div>
            </div>
          </div>
        )}
      </div>
    </section>
  );
};

export default ArrivalOne;